def correction_rate_by_type(conn: sqlite3.Connection) -> dict:
    rows = conn.execute(
        """SELECT correction_type, COUNT(*) as cnt FROM corrections
           GROUP BY correction_type ORDER BY cnt DESC""",
    ).fetchall()
    total = sum(r[1] for r in rows)
    return {
        r[0]: {"count": r[1], "pct": round(r[1] / total * 100, 1) if total else 0}
        for r in rows
    }
# Example output:
# {"factual": {"count": 48, "pct": 42.5}, "scope": {"count": 30, "pct": 26.5}, ...}
